import { useState } from 'react';
import './App.css';

function App() {
  const [count, setCount] = useState(0);

  return (
    <div className="App">
      <div className="counter-card">
        <h1>Counter App</h1>
        <p className="count-value">{count}</p>
        <div className="button-row">
          <button type="button" onClick={() => setCount(count - 1)} aria-label="decrease">
            -
          </button>
          <button type="button" onClick={() => setCount(0)}>
            Reset
          </button>
          <button type="button" onClick={() => setCount(count + 1)} aria-label="increase">
            +
          </button>
        </div>
      </div>
    </div>
  );
}

export default App;
